"""
MKT Original Commentary — 2 Timothy chapters 1–4 (all 83 missing verses)
Run: python3 scripts/zc-original-2timothy-1-4.py

Key translation decisions:
- anazōpyrein (1:6): 'fan into flame / rekindle' — the dying-coal metaphor
- sōphronismos (1:7): 'self-discipline/sound-mindedness' — Pastoral Epistles' distinctive
- parathēkē (1:12,14): 1:12 = what Paul deposits with God; 1:14 = what God entrusts to Timothy
- orthotomounta (2:15): 'cutting straight' — hapax; the straight-furrow artisan image
- theopneustos (3:16): 'breathed out by God' — hapax; God as subject breathing out Scripture
- spendomai (4:6): 'I am poured out as a drink offering' — libation sacrifice image
- artios / exērtismenos (3:17): 'complete / thoroughly equipped' — dual use of artios root
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(layer, book):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(layer, book, data):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

ORIGINAL = {
  "1": {
    "1": '<p><em>Kata epangelian zōēs tēs en Christō Iēsou</em> (according to the promise of life that is in Christ Jesus): the apostolate is grounded in and oriented toward a divine promise. <em>Epangelia</em> (promise) — the covenantal promise of life; the qualifier "in Christ Jesus" locates the promise not in general religious hope but in the specific person and history of the Messiah. Unlike Romans 1:1 (set apart for the gospel) or Galatians 1:1 (not from humans), the qualification here is eschatological: Paul\'s apostleship is defined by its goal — the life promised and now manifest in Christ.</p>',
    "2": '<p><em>Gnēsiō teknō</em> (genuine/true child): <em>gnēsios</em> = legitimate, not spurious — the same adjective used in Phil 4:3 for the "loyal yokefellow." In the ancient world a gnēsios child was one of recognized legitimacy within the family, as opposed to a spurious or adopted child. Timothy\'s apostolic legitimacy as Paul\'s heir is signaled by this single adjective. The triad <em>charis, eleos, eirēnē</em> (grace, mercy, peace) expands the standard Pauline greeting (grace + peace) with <em>eleos</em> (mercy) — the specifically OT covenantal-loyalty term (<em>hesed</em>) that appears in the Pastoral Epistles\' greetings but not Paul\'s other letters.</p>',
    "3": '<p><em>Hō latreuō apo progonōn en katharā syneidēsei</em> (whom I serve from forebears with clean conscience): <em>latreuō</em> is specifically priestly-cultic worship language (used for service at the temple and to God), applied here to Paul\'s apostolic ministry — his entire life of ministry is priestly service. <em>Apo progonōn</em> (from forebears/ancestors) — Paul\'s service to God is continuous with his Jewish heritage, not a break from it; he worships the God of his ancestors in Christ. <em>Katharā syneidēsei</em> (clean/clear conscience) — <em>syneidēsis</em> (conscience) is prominent in the Pastoral Epistles (1 Tim 1:5, 19; 3:9; 4:2; Tit 1:15); a clear conscience is not innocence but the result of living consistently with what one knows to be true.</p>',
    "4": '<p><em>Epipothō se idein</em> (I long to see you): <em>epipotheō</em> is a strong longing-verb (the prefix <em>epi-</em> intensifies the desire); it appears in Phil 1:8 for Paul\'s intense longing for the Philippians. The personal warmth of the closing section of 2 Timothy is striking — this is the most intimate of the Pastoral Epistles. <em>Tōn dakryōn sou</em> (your tears) — probably the tears at their last parting; the memory of Timothy\'s emotional farewell is the spur to Paul\'s longing. <em>Hina charas plērōthō</em> (so that I may be filled with joy) — the joy of reunion that would complete what the tears began.</p>',
    "5": '<p><em>Hypomnēsin labōn tēs en soi anypokritou pisteōs</em> (having received/taken a reminder of the sincere faith in you): <em>hypomnēsis</em> = the act of calling to mind, a reminder that reactivates memory. <em>Anypokritus</em> (sincere, unhypocritical) — <em>a-</em> + <em>hypokritēs</em> (actor, one who plays a part); sincere faith is contrasted with performed faith. The same adjective appears in 1 Tim 1:5 for love that is unhypocritical. <em>Prōton en tē mammē sou Lōidi kai tē mētri sou Eunikē</em> (first in your grandmother Lois and your mother Eunice) — the feminine names are Jewish diaspora names; the multigenerational faith chain is the personal embodiment of the Deuteronomic transmission mandate (Deut 6:7).</p>',
    "6": '<p><em>Anazōpyrein to charisma tou theou</em> (to fan into flame / rekindle the gift of God): <em>anazōpyreō</em> — <em>ana</em> (again/up) + <em>zōpyron</em> (live coal, ember); the compound suggests rekindling a dying or banked fire. The image is not of a fire that has gone out but of one whose coals need fanning to full flame. <em>Charisma</em> (gift of grace) — the specific gift given at ordination; what is "in" Timothy through the laying on of Paul\'s hands (<em>dia tēs epitheseōs tōn cheirōn mou</em>). The gift can apparently diminish in vigor without being lost — hence the call to fan it actively rather than assume it burns automatically.</p>',
    "7": '<p><em>Pneuma deilian</em> (spirit of cowardice/timidity): <em>deilia</em> — the only NT occurrence; <em>deilos</em> (coward) appears in Matt 8:26 and Rev 21:8. The spirit of cowardice is contrasted with the spirit of <em>dynamis</em> (power), <em>agapē</em> (love), and <em>sōphronismos</em> (self-discipline/sound-mindedness). <em>Sōphronismos</em> — related to <em>sōphrōn</em> (sound-minded, self-controlled), a major virtue in the Pastoral Epistles; here in its abstract noun form (only here in NT). The Pastoral Epistles\' characteristic triad of virtues — power, love, and disciplined soundness of mind — maps closely onto the Stoic virtues but is grounded in the divine gift rather than human cultivation.</p>',
    "8": '<p><em>Mē oun epaischynthēs to martyrion tou Kyriou hēmōn</em> (do not therefore be ashamed of the testimony of our Lord): <em>epaischynomai</em> (to be ashamed) — the shame-avoidance verb connects to the honor-shame dynamics of the Greco-Roman world; Paul has just declared he is not ashamed (v. 12). The call not to be ashamed presupposes that social pressure toward shame is real — imprisonment and public humiliation attach to Paul as stigmata. <em>Synkakopathēson</em> (suffer with me / share in suffering) — the compound verb (<em>syn</em> + <em>kakopatheo</em>) makes suffering a partnership; Timothy is invited into co-participation in Paul\'s imprisonment-sufferings. <em>Kata dynamin theou</em> (according to the power of God) — suffering is done in reliance on divine power, not human endurance.</p>',
    "9": '<p><em>Sōsantos hēmas kai kalesantos klēsei hagia</em> (who saved us and called us with a holy calling): two aorist participles summarize the entire divine initiative — saving and calling are prior acts that precede Timothy\'s and Paul\'s response. <em>Ou kata ta erga hēmōn alla kata idian prothesis kai charin</em> (not according to our works but according to his own purpose and grace) — <em>prothesis</em> (purpose/intention; literally the setting-forth of something); the divine purpose is the ground of salvation. <em>Pro chronōn aiōniōn</em> (before eternal times) — the pre-temporal dimension of grace: given before time began, now revealed in Christ\'s appearing. The structure anticipates the Ephesians 1 framework of pre-temporal divine election.</p>',
    "10": '<p><em>Katargēsantos men ton thanaton</em> (having abolished/nullified death): <em>katargeō</em> = to render inoperative, to nullify, to make of no effect; Paul uses the same verb in 1 Cor 15:26 (the last enemy to be abolished is death) and 1 Cor 2:6 (the rulers of this age being abolished). Death is not destroyed in the sense of ceasing to exist but is rendered powerless — stripped of its former dominion. <em>Phōtisantos de zōēn kai aphtharsian</em> (but illuminating life and immortality) — the gospel as a light that illuminates (makes visible) what was previously hidden in darkness: life (<em>zōē</em>) and incorruptibility (<em>aphtharsia</em>). <em>Epiphaneia</em> (appearing) — the Pastoral Epistles\' signature Christological term for both the incarnation (here) and the Parousia (4:1, 8; 1 Tim 6:14; Tit 2:13).</p>',
    "11": '<p><em>Kēryx kai apostolos kai didaskalos</em> (herald and apostle and teacher): the three-fold ministerial designation. <em>Kēryx</em> (herald) — specifically the public crier who makes official proclamations; the most basic description of Paul\'s proclamatory function. <em>Apostolos</em> (apostle) — the commissioned envoy sent with the authority of the sender. <em>Didaskalos</em> (teacher) — the one who provides systematic instruction. The three titles cover the full range: proclamation (kēryx), authority and sending (apostolos), and sustained instruction (didaskalos). Elsewhere Paul uses herald (kēryx) language only in 1 Tim 2:7 and here — it is a more public-rhetorical term than "apostle."</p>',
    "12": '<p><em>Oida gar hō pepisteukai</em> (for I know whom I have believed/trusted): the perfect tense <em>pepisteukai</em> (I have believed and continue believing) describes the settled, completed act of trust that Paul stands in. <em>Hō</em> (whom) — the object of trust is a person, not a proposition. <em>Kai pepeismai hoti dynatos estin tēn parathēkēn mou phylaxai</em> (and I am convinced that he is able to guard my deposit): here <em>parathēkē mou</em> = what Paul has deposited with God — his life, ministry, and ultimate welfare. This is the reverse of 1:14 where <em>parathēkē</em> is what God has deposited with Timothy. Paul\'s confidence in suffering is grounded in the reliability of the one who holds his deposit in trust.</p>',
    "13": '<p><em>Hypotyōsin echōn hygiainontōn logōn hōn par\' emou ēkousas</em> (hold the pattern/sketch of sound words which you heard from me): <em>hypotypōsis</em> (pattern, outline, sketch) — the architectural or artistic term for a preliminary sketch or model from which the finished work is constructed; the sound words Paul taught are the <em>hypotypōsis</em> Timothy holds as his working model. <em>Hygiainontōn logōn</em> (of sound/healthy words) — the medical metaphor (<em>hygiainō</em> = to be healthy) characteristic of the Pastoral Epistles. <em>En pistei kai agapē tē en Christō Iēsou</em> (in faith and love that are in Christ Jesus) — the sphere in which the pattern is held and transmitted.</p>',
    "14": '<p><em>Tēn kalēn parathēkēn phylaxon dia pneumatos hagiou</em> (guard the good deposit through the Holy Spirit): the imperative <em>phylaxon</em> (guard) contrasts with the indicative <em>phylaxai</em> in v. 12 — God guards Paul\'s deposit; Timothy is commanded to guard the deposit entrusted to him. The agent of guarding is the Holy Spirit who dwells in us — the imperative is not a solo effort but a Spirit-enabled fidelity. The double use of <em>parathēkē</em> in vv. 12 and 14 creates a theological chiasm: what Paul entrusts to God (v.12) is the model for what God entrusts to Timothy (v.14).</p>',
    "15": '<p><em>Apestraphēsan me pantes hoi en tē Asia</em> (all those in Asia turned away from me): <em>apostrephō</em> = to turn the face away, to avert; the gesture of social disavowal. "All in Asia" is a broad rhetorical statement for the widespread desertion of Paul at his arrest; the named examples (Phygelus and Hermogenes) are not otherwise known. Asia (the Roman province) was Paul\'s primary ministry area — Ephesus its capital. The desertion is not necessarily apostasy but the social abandonment of a shamefully imprisoned man; association with a prisoner endangered the reputation and safety of one\'s household.</p>',
    "16": '<p><em>Anepsyxen me</em> (he refreshed me): <em>anapsychō</em> = literally to cool, give air to breathe; the compound of <em>ana</em> (again) + <em>psychō</em> (to breathe, cool); a hapax in the NT. The physical imagery of giving air to breathe in the stifling context of Roman imprisonment is acute — Onesiphorus\'s visits provided literal relief in a hot, airless cell. <em>Ouk epaischynthē tēn halysis mou</em> (not ashamed of my chain) — the single chain (<em>halysis</em>, singular) attached a prisoner to a guard; Onesiphorus\'s willingness to visit publicly acknowledged association with a shamed prisoner.</p>',
    "17": '<p><em>Alla genomenon en Romē spoudaiōs ezētēsen me kai heuren</em> (but when in Rome he searched diligently for me and found me): the aorist narrative of deliberate effort — <em>spoudaiōs</em> (diligently, eagerly) combined with <em>ezētēsen</em> (he searched) and <em>heuren</em> (he found). Roman imprisonment in the first century did not have a fixed location; prisoners awaiting trial might be kept in various places depending on their legal status and social connections. Onesiphorus\'s search through the city for Paul suggests some difficulty in locating the specific prison or custody situation.</p>',
    "18": '<p><em>Dōē autō ho Kyrios heurein eleos para Kyriou en ekeinē tē hēmera</em> (may the Lord grant that he find mercy from the Lord on that day): the optative <em>dōē</em> (may he grant) expresses a prayer-wish; the repetition "Lord... from the Lord" is notable — some see a reference to God the Father and the Lord Jesus as the eschatological judge (cf. 4:8: "the Lord, the righteous Judge"), making this a Trinitarian-inflected prayer. <em>En ekeinē tē hēmera</em> (on that day) — the Day of Judgment, the eschatological day of reckoning that the Pastoral Epistles consistently look toward (1:12; 4:8). The personal concern for Onesiphorus\'s eschatological welfare matches the depth of personal gratitude expressed in vv. 16-17.</p>'
  },
  "2": {
    "1": '<p><em>Endynamou en tē chariti tē en Christō Iēsou</em> (be strengthened in the grace that is in Christ Jesus): <em>endynamoō</em> (present passive imperative) — to be continuously empowered/strengthened, with the passive implying divine enabling. The source of strength is grace — the unearned gift-relationship in Christ — rather than Timothy\'s own resources. The opening imperative of ch. 2 answers the preceding chapters\' portrait of Paul\'s suffering: Timothy is not left to find strength in himself but is directed to the same grace that sustains Paul.</p>',
    "2": '<p><em>Ha ēkousas par\' emou dia pollōn martyrōn, tauta parathes pistois anthrōpois, hoitines hikanoi esontai kai heterous didaxai</em> (what you heard from me through many witnesses, entrust these things to faithful people who will also be qualified to teach others): the apostolic tradition-transmission chain in one verse: Paul → Timothy → faithful people → others (four generations). <em>Dia pollōn martyrōn</em> (through many witnesses) — the instruction passed through many witnesses makes Timothy\'s knowledge both publicly verified and communally accountable. <em>Parathes</em> (entrust, deposit) — <em>paratithēmi</em>, the same root as <em>parathēkē</em> (deposit); the tradition-transmission is another act of deposit-entrustment.</p>',
    "3": '<p><em>Synkakopathēson hōs kalos stratiotēs Christou Iēsou</em> (suffer together as a good soldier of Christ Jesus): the second use of <em>synkakopatheo</em> (1:8; 2:3) — sharing in bad/evil suffering as a compound act. The first of three metaphors in vv. 3-6 (soldier, athlete, farmer), all pointing to the necessity of disciplined endurance before reward. <em>Kalos stratiotēs</em> (good soldier) — the military metaphor was common in Stoic and Cynic discourse for the philosopher who endures hardship.</p>',
    "4": '<p><em>Oudeis strateuomenos empleketai tais tou biou pragmateiais</em> (no one serving as a soldier gets entangled in civilian affairs): <em>emplekō</em> = to entangle, interweave; the soldier who is entangled in civilian business (<em>pragmateiai</em>) fails to please his commanding officer. <em>Stratologēsanti</em> (to the one who recruited/enlisted him) — the participle describes the commanding officer who selected and enrolled the soldier. The application to ministry: ministerial focus requires freedom from civilian entanglements. This was a real issue — first-century artisans in ministry might be tempted to combine their trade with itinerant teaching in ways that compromised both.</p>',
    "5": '<p><em>Ean de kai athlē tis, ou stephanoūtai ean mē nomimōs athlēsē</em> (but if anyone competes as an athlete, he does not receive the crown unless he competes lawfully): <em>athlē</em> (competes as an athlete, strives in the contest) — the verb is rare; <em>athlos</em> = contest, struggle. <em>Stephanoō</em> (to crown) — the victor\'s wreath at the great games; the image connects to 4:8 (the crown of righteousness). <em>Nomimōs</em> (lawfully, according to the rules) — competitors who violated the rules of the games (diet requirements, legitimate birth, rule-following in the contest itself) were disqualified regardless of performance. Lawful conduct precedes the crown.</p>',
    "6": '<p><em>Ton kopiōnta geōrgon dei prōton tōn karpōn metalambanein</em> (the hard-working farmer should be first to receive a share of the crops): <em>kopiaō</em> (to toil exhaustingly) — Paul\'s standard term for his own apostolic labor (1 Cor 15:10; Gal 4:11; Phil 2:16; Col 1:29); the <em>kopiōnta geōrgon</em> (toiling farmer) is another image for the minister who labors to exhaustion. <em>Dei prōton metalambanein</em> (should be first to receive) — the laborer has a right to benefit from the harvest; the same principle applies in 1 Tim 5:17-18 (the elder worthy of double honor).</p>',
    "7": '<p><em>Noei ho legō</em> (understand/reflect on what I am saying): the brief direct address invites Timothy to do the exegetical work of applying the three metaphors himself. <em>Dōsei gar soi ho Kyrios synesin en pasin</em> (for the Lord will give you understanding in all things) — the divine grant of understanding answers the human exercise of reflection; understanding is both sought (reflect on this) and given (the Lord grants it). <em>Synesis</em> (understanding, comprehension) — the capacity to bring together disparate pieces into a coherent grasp; here it is a gift of the Lord.</p>',
    "8": '<p><em>Mnēmoneue Iēsoun Christon egēgermenon ek nekrōn</em> (remember Jesus Christ raised from the dead): the present imperative <em>mnēmoneue</em> (keep remembering, hold in memory) — not a one-time recall but continuous memory. The object of memory is specified in its most theologically dense form: Jesus Christ, raised from the dead, from the seed of David. <em>Ek spermatos Dauid</em> (from the seed of David) — the Davidic lineage anchors the resurrection claim in covenantal-historical promise; the raised Messiah is the promised Davidic heir. <em>Kata to euangelion mou</em> (according to my gospel) — Paul\'s personalized formula for the core proclamation.</p>',
    "9": '<p><em>Hēn kakourgos dēsmiōs</em> (for which I suffer as a criminal in chains): <em>kakourgos</em> = evildoer, criminal — the same Greek word used for the criminals crucified alongside Jesus (Luke 23:32-33, 39). Paul occupies the same social position as the criminals of the crucifixion narrative: chained as a criminal in Roman custody. <em>All\' ho logos tou theou ou dedetai</em> (but the word of God is not chained) — the contrast between the imprisoned apostle and the unchained word: Paul\'s physical constraints cannot limit the gospel\'s movement. The word goes where Paul cannot.</p>',
    "10": '<p><em>Panta hypomenō dia tous eklektous</em> (I endure all things for the sake of the elect): <em>hypomenō</em> (to endure under, remain under) — the compound of remaining under a burden rather than fleeing it. <em>Tous eklektous</em> (the elect) — Paul\'s suffering has an ecclesial and eschatological purpose: the elect who will obtain salvation through the gospel proclaimed through Paul\'s ministry. <em>Sōtērias tychōsin tēs en Christō Iēsou meta doxēs aiōniou</em> (may obtain salvation in Christ Jesus with eternal glory) — <em>tynchanō</em> = to happen upon, attain; the elect "happen upon" salvation through the proclamation that Paul\'s endurance makes possible.</p>',
    "11": '<p><em>Pistos ho logos</em> (faithful/trustworthy is the word): the Pastoral Epistles\' formula for introducing a pre-formed saying or hymn fragment (1 Tim 1:15; 3:1; 4:9; Tit 3:8). What follows in vv. 11-13 is a tightly structured four-line antithetical series: death/life; endurance/reign; disowning/disowned; faithlessness/faithfulness. <em>Ei gar synapethanomen, kai syzēsomen</em> (for if we died with him, we will also live with him) — the first condition applies the baptismal death-burial-resurrection pattern (Rom 6:4-8) to eschatological hope; dying with Christ grounds living with Christ.</p>',
    "12": '<p><em>Ei hypomenomen, kai symbasileusomen</em> (if we endure, we will also reign with him): the endurance-reigning pair extends the death-life parallel; faithful endurance now leads to co-reign later (cf. Rev 20:4). <em>Ei arnēsometha, kakeinōs arnēsetai hēmas</em> (if we disown him, he will also disown us): the warning echoes Jesus\'s logion (Matt 10:33; Luke 12:9) — the one who denies Christ before people will be denied before the Father. The mutual-denial clause is the sharpest point in the series, directed at the pressure Timothy faces to disown the imprisoned Paul.</p>',
    "13": '<p><em>Ei apistoumen, ekeinos pistos menei</em> (if we are faithless, he remains faithful): the fourth and theologically climactic clause breaks the symmetry — unlike the previous three, this one does not mirror the human action in the divine response. <em>Apistountes</em> (faithless) and <em>pistos menei</em> (remains faithful) — God\'s faithfulness is not contingent on human faithfulness. <em>Arnēsasthai gar heauton ou dynatai</em> (for he cannot deny himself) — the ground of his unfailing faithfulness: self-denial is ontologically impossible for the self-consistent God. This clause functions as the theological foundation for the entire hymn-fragment: the asymmetry between human inconstancy and divine constancy.</p>',
    "14": '<p><em>Tauta hypomimnēske, diamartyromenos enōpion tou theou</em> (remind them of these things, solemnly charging before God): <em>hypomimnēskō</em> (to remind by bringing to mind) — the task of pastoral memory-management; the congregation needs continuous reminding of established truth. <em>Mē logomachein</em> (not to quarrel about words/engage in word-battles) — <em>logomachia</em> (word-battle) appears also in 1 Tim 6:4; the quarrel-about-words is a recognized vice of false teachers; it produces nothing useful (<em>ep\' ouden chrēsimon</em>) and subverts the hearers (<em>epi katastrophē tōn akouontōn</em>).</p>',
    "15": '<p><em>Spoudason seauton dokimon parastēsai tō theō</em> (be diligent to present yourself approved to God): <em>spoudazō</em> (to be diligent, make haste, be eager) — the verb of intentional effort. <em>Dokimos</em> (approved, tested and found genuine) — the metallurgical term for metal tested and found to be without alloy; the approved minister has been tested and found genuine. <em>Orthotomounta ton logon tēs alētheias</em> (cutting straight the word of truth) — <em>orthotomeō</em> is a hapax in the NT; it combines <em>orthos</em> (straight, correct) with <em>temnō</em> (to cut); the image is either of the road-builder cutting a straight path through terrain, or the artisan who cuts clean and straight. The word of truth must be handled with the precision of a skilled craftsman.</p>',
    "16": '<p><em>Tas de bebēlous kenophōnias periistaso</em> (but avoid godless empty chatter): <em>periistēmi</em> (to stand around, avoid, shun) — the avoidance is active evasion. <em>Bebēlos kenophōnia</em> (godless empty-chatter) — <em>bebēlos</em> = profane, accessible to anyone (not restricted to the holy); <em>kenophōnia</em> = empty-sounding speech, void of content. <em>Prokopsousin gar epi pleion asebeias</em> (for they will advance further into ungodliness) — the empty chatter doesn\'t stay static but progresses; <em>prokoptō</em> (to cut forward, advance) is used ironically: they advance, but toward greater ungodliness rather than toward truth.</p>',
    "17": '<p><em>Gangraina hexei</em> (will have/spread like gangrene): <em>gangraina</em> (gangrene) — the spreading necrosis of tissue; the medical metaphor is precise: false teaching, like gangrene, spreads from the infected tissue to healthy tissue, destroying community health from within. <em>Hymenaeus kai Philētos</em> — Hymenaeus appears also in 1 Tim 1:20 (handed over to Satan); Philetus is otherwise unknown. The naming of specific individuals is a characteristic feature of the Pastoral Epistles\' polemical sections — the error has real, identifiable proponents.</p>',
    "18": '<p><em>Hoi peri tēn alētheian ēstochēsan, legontes tēn anastasin ēdē gegonenai</em> (who missed the mark about the truth, saying the resurrection has already happened): <em>ēstocheō</em> (to miss the mark, fail to hit the target) — the error is not ignorance but misdirection; they are shooting but missing. The specific error — <em>anastasin ēdē gegonenai</em> (the resurrection has already taken place) — is a form of over-realized eschatology; it absorbs the future bodily resurrection into a present spiritual event (possibly baptismal death-and-resurrection experienced as total fulfillment). This denial destroys (<em>anatrepousin</em> = to overturn, upset) the faith of some.</p>',
    "19": '<p><em>Ho mentoi stereos themelios tou theou hestēken</em> (nevertheless the solid foundation of God stands firm): <em>stereos</em> (solid, firm, hard) contrasts with the collapsing faith of those overthrown by the error. The foundation is <em>God\'s</em> foundation — not the false teachers\' construction. <em>Echōn tēn sphragida tautēn</em> (having this seal/inscription) — a foundation stone with an inscription was a known feature of significant public buildings. The two inscriptions are: (1) <em>Egnō Kyrios tous ontas autou</em> (the Lord knows those who are his) — echoing Num 16:5 LXX (God knows those who belong to him; YHWH\'s recognition of his own in the Korah rebellion); and (2) <em>Apostētō apo adikias pas ho onomazōn to onoma Kyriou</em> (let everyone who names the Lord\'s name depart from unrighteousness) — the positive corollary.</p>',
    "20": '<p><em>En megalē de oikia ouk estin monon skeuē chrysa kai argyra alla kai xylina kai ostrakina</em> (in a large house there are not only gold and silver vessels but also wood and clay): the <em>oikia</em> (great house) metaphor for the church or the divine household; the vessels (<em>skeuē</em>) range from precious (<em>chrysa, argyra</em>) to common (<em>xylina, ostrakina</em>). <em>Ha men eis timēn ha de eis atimian</em> (some for honor and some for dishonor) — the distinction between honorable and dishonorable purposes. The metaphor raises the question of whether the vessels are differentiated by divine selection or by their own purification — v. 21 answers the latter.</p>',
    "21": '<p><em>Ean oun tis ekkatharē heauton apo toutōn</em> (if anyone cleanses himself from these things): the reflexive <em>heauton</em> (himself) places the initiative for purification with the individual; the passive vessel becomes active in self-cleansing. <em>Estai skeuos eis timēn</em> (he will be a vessel for honor) — the shift from passive vessel to active purifier to honored vessel tracks the movement from contamination through decision to usefulness. <em>Hēgiasmenon, euchrēston tō despotē, eis pan ergon agathon hētoimasmenon</em> (sanctified, useful to the master, prepared for every good work) — three qualities of the honored vessel: consecrated, serviceable, and ready.</p>',
    "22": '<p><em>Tas neoterkas epithumias pheuge</em> (flee youthful desires): <em>neoterikos</em> (youthful, belonging to youth) — the desires specifically associated with youth: impetuosity, passion for novelty, love of argument, sexual desire. <em>Pheuge</em> (flee) — the same verb as 1 Tim 6:11 (flee these things); active flight rather than passive resistance. The four virtues to pursue — <em>dikaiosynē, pistin, agapēn, eirēnēn</em> (righteousness, faith, love, peace) — are communal: pursued <em>meta tōn epikaloumonōn ton Kyrion ek katharas kardias</em> (with those who call on the Lord from a pure heart); virtue is not a solo achievement.</p>',
    "23": '<p><em>Tas de mōras kai apaideutos zētēseis paraitou</em> (but refuse/decline foolish and uneducated speculations): <em>mōros kai apaideutos</em> (foolish and undisciplined/uneducated) — the speculations are critiqued on two grounds: intellectual (foolish, without wisdom) and formational (undisciplined, without the formation of genuine education). <em>Paraiteomai</em> (to decline, excuse oneself from, refuse) — the verb of polite but firm refusal; the minister who engages the controversies legitimizes them. <em>Gennōsin machas</em> (they generate quarrels) — the output of foolish speculation is not light but conflict.</p>',
    "24": '<p><em>Doulos de Kyriou ou dei machesthai alla ēpion einai pros pantas</em> (the Lord\'s servant must not be quarrelsome but gentle toward all): <em>doulos Kyriou</em> (servant/slave of the Lord) — the OT title (<em>ebed YHWH</em>) applied to Moses (Deut 34:5), Joshua (Josh 24:29), and David (Ps 89:3); its application to the Christian minister places him in the prophetic-leadership succession. <em>Ēpios</em> (gentle, mild, kind) — the quality of the nursing mother in 1 Thess 2:7; the antithesis of contentious. <em>Didaktikon</em> (able to teach) and <em>anexikakos</em> (patient under evil, tolerant) complete the portrait of the minister who absorbs opposition rather than reflecting it.</p>',
    "25": '<p><em>En prautēti paideuonta tous antitithemenous</em> (gently instructing those who oppose): <em>prautēs</em> (gentleness, meekness) — one of the Spirit\'s fruit (Gal 5:23); the minister who instructs opponents in gentleness rather than confrontation. <em>Mēpote dōē autois ho theos metanoian eis epignōsin alētheias</em> (whether God might grant them repentance into knowledge of the truth) — the optative <em>mēpote dōē</em> expresses hope rather than certainty; repentance is a divine grant, not a human achievement. <em>Epignōsis</em> (full/precise knowledge) — the intensive compound in the Pastoral Epistles marks genuine knowledge of truth as the goal toward which repentance leads.</p>',
    "26": '<p><em>Ananēpsōsin ek tēs tou diabolou pagidos</em> (that they may come to their senses out of the devil\'s trap): <em>ananēphō</em> = to become sober again, to recover one\'s senses (as from intoxication or sleep) — the hapax image is of those who have been mentally captured requiring an awakening to reality. <em>Pagis tou diabolou</em> (trap of the devil) — the hunting snare; the opponents are simultaneously captors and captives: taken captive by the devil (<em>ezōgrēmenoi hyp\' autou</em>) to do his will (<em>eis to ekeinon thelēma</em>). The ambiguous pronoun <em>ekeinon</em> (his) refers most naturally to the devil: captured to do the devil\'s will.</p>'
  },
  "3": {
    "1": '<p><em>En eschatais hēmerais</em> (in the last days): the eschatological temporal marker that frames the entire vice list of vv. 1-9. The "last days" in Jewish and early Christian thought referred to the age inaugurated by the Messiah\'s coming — Paul consistently treats the present age as the "last days" (1 Cor 10:11; Heb 1:2). <em>Enestēsontai kairoi chalepoi</em> (difficult/dangerous times will come) — <em>chalepos</em> = difficult, dangerous, fierce; the same adjective used in Matt 8:28 for the Gadarene demoniacs who were too fierce to pass. The "last days" bring not only eschatological glory but eschatological conflict.</p>',
    "2": '<p>The vice list of vv. 2-4 is one of the densest in the NT. <em>Philautoi</em> (self-lovers) — the compound <em>philos</em> + <em>autos</em>; the Stoic tradition condemned <em>philautia</em> as the root of moral failure. <em>Philargyroi</em> (money-lovers) — the same compound structure as <em>philautia</em>; love of self and love of money are the twin root vices. <em>Alazones</em> (boastful/swaggering) — those who claim more than they possess; <em>hyperēphanoi</em> (arrogant/overweening) — those who look down on others. <em>Blasphēmoi</em> (slanderous, abusive) — applied here to speech that injures human honor rather than divine honor. <em>Goneusin apeitheis</em> (disobedient to parents) — the violation of the fifth commandment, which the Stoics also placed high among social obligations.</p>',
    "3": '<p><em>Astorgoi</em> (without natural affection/family love): <em>storgē</em> is the specific term for the natural love of family members (especially parents and children); its absence marks the breakdown of the most basic social bond. <em>Aspondoi</em> (irreconcilable, without truce) — those who will not negotiate even a temporary truce; the term comes from the practice of <em>spondai</em> (libations poured at treaty-making). <em>Diaboloi</em> (slanderous, devil-like) — the same word as "devil" (<em>diabolos</em> = the slanderer); slanderers act in the devil\'s character. <em>Akrateis</em> (without self-control) — the opposite of <em>enkrateia</em> (self-control), a key Stoic and Pastoral Epistles virtue. <em>Anēmeroi</em> (savage, brutal) — <em>a-</em> + <em>hēmeros</em> (tame, cultivated); the savage who has not been civilized.</p>',
    "4": '<p><em>Prodotai</em> (traitors, betrayers) — <em>prodidōmi</em> = to hand over, betray; the one who gives over those who trusted them. <em>Propeteis</em> (rash, reckless) — literally "falling forward," acting impulsively without deliberation. <em>Tetyphōmenoi</em> (puffed up, blinded by smoke) — the perfect passive of <em>typhōō</em> (to fill with smoke/vapor), creating self-inflated blindness; the same verb as 1 Tim 3:6 and 6:4. <em>Philēdonoi mallon ē philotheoi</em> (lovers of pleasure rather than lovers of God) — the chiastic reversal: <em>philo-</em> compounds define what one loves; the contrast between loving pleasure and loving God is the theological heart of the vice list.</p>',
    "5": '<p><em>Echontes morphōsin eusebeias tēn de dynamin autēs ērnēmenoi</em> (having the form of godliness but denying its power): <em>morphōsis</em> (form, appearance, outward shape) — in Platonic thought the <em>morphē</em> is the form that gives shape; here it is the external religious form without the substance. The vice list of vv. 2-4 is not about openly irreligious people but about those who maintain religious practice (<em>morphōsin eusebeias</em>) while being inwardly corrupt. <em>Apotrepou</em> (turn away from, avoid) — the present imperative of aversion; Timothy is to continuously turn away from such people.</p>',
    "6": '<p><em>Endunontes eis tas oikias kai aichmalōtizontes gynaikaria sesōreumena hamartiais</em> (worming their way into houses and capturing weak women loaded down with sins): <em>endunomai</em> (to creep in, worm in) — the stealthy entry of those who avoid public scrutiny. <em>Gynaikaria</em> — diminutive of <em>gynē</em> (woman); the diminutive may be dismissive (little women) or may indicate socially marginal or young women. <em>Sesōreumena hamartiais</em> (heaped/loaded with sins) — <em>sōreuō</em> = to heap up; the passive image of sins piled onto the person. <em>Agomena epithumiais poikilais</em> (led by various desires) — the varied desires that make them susceptible to manipulation.</p>',
    "7": '<p><em>Pantote manthanonta kai mēdepote eis epignōsin alētheias elthein dynamena</em> (always learning and never able to come to a knowledge of the truth): the irony of perpetual learning without arriving at truth; learning without formation. The characterization applies to those who accumulate teaching from the false teachers without the transformative knowledge that genuine <em>epignōsis alētheias</em> (full knowledge of truth) would produce. Perpetual learning as a substitute for genuine knowledge was a recognized critique in ancient rhetoric — the sophist\'s audience perpetually sought new teaching rather than living by what they already knew.</p>',
    "8": '<p><em>Hon tropon Iannes kai Iambrēs antestēsan Mōysei</em> (just as Jannes and Jambres opposed Moses): Jannes and Jambres are not named in the OT (Exod 7:11 refers to "the magicians of Egypt"), but they are named in Jewish tradition: in the Damascus Document (CD 5:18-19), in Targum Pseudo-Jonathan on Exod 7:11, and referenced in Origen and other fathers. Their names were widely known in first-century Jewish circles; Paul\'s reference assumes the audience knows the tradition. The magicians who opposed Moses through counterfeit miracles are the type for those who oppose genuine apostolic teaching through counterfeit wisdom.</p>',
    "9": '<p><em>All\' ou prokopsousin epi pleion</em> (but they will not advance further): the irony of <em>prokoptō</em> (advance/progress) used for the false teachers\' limited reach; their "progress" is bounded. <em>Hē gar anoia autōn ekdēlos estai pasin</em> (for their folly will be plain to all) — <em>ekdēlos</em> (thoroughly manifest, plain to see) — the prefix <em>ek-</em> intensifies the visibility; what is currently hidden (their true character) will become fully exposed. As with Jannes and Jambres whose folly was exposed when Moses\' serpent swallowed theirs, the false teachers\' folly has a fixed horizon.</p>',
    "10": '<p><em>Sy de paramēkolouthēkas mou tē didaskalia, tē agōgē, tē prothesei</em> (but you have closely followed/carefully observed my teaching, conduct, purpose): <em>parakoloutheo</em> (to follow alongside, observe closely from proximity) — the intensive prefix <em>para</em> (alongside) + <em>akoloutheo</em> (to follow); the disciple who shadows the teacher, observing not just the words but the entire life. The nine-item list that follows — teaching, conduct, purpose, faith, patience, love, endurance, persecutions, sufferings — is a catalogue of Paul\'s entire apostolic life as observed by Timothy from close proximity. It is biography as example.</p>',
    "11": '<p><em>Tois diōgmois, tois pathēmasin, hoia moi egeneto en Antiocheia, en Ikoniō, en Lystrois</em> (persecutions, sufferings — what kinds happened to me in Antioch, Iconium, Lystra): the three cities of Paul\'s first missionary journey (Acts 13-14) where he was stoned, driven out, and left for dead. Timothy was from Lystra (Acts 16:1) — he knew these persecutions not merely by report but by local knowledge and perhaps personal memory. <em>Hoious diōgmous hypēnenka</em> (what persecutions I endured) — <em>hypomenō</em> (to endure under); the Lord\'s rescue from all (<em>ek pantōn me errysato ho Kyrios</em>) grounds the call to endurance.</p>',
    "12": '<p><em>Pantes de hoi thelontes zēn eusebōs en Christō Iēsou diōchthēsontai</em> (indeed all who want to live godly in Christ Jesus will be persecuted): the universal principle: godly living in Christ produces persecution. <em>Diōchthēsontai</em> (will be persecuted) — future passive; the persecutions are not accidental but the inevitable consequence of the counter-cultural life. This principle contextualizes the specific persecutions Paul listed in v. 11 as instances of the universal pattern rather than exceptional misfortunes.</p>',
    "13": '<p><em>Ponēroi de anthrōpoi kai goētes prokopsousin epi to cheiron</em> (but evil people and swindlers/impostors will advance to worse): <em>goēs</em> (swindler, impostor, charlatan, juggler) — originally one who uses spells and incantations, then broadly a deceiver. The ironic use of <em>prokoptō</em> (advance/progress) for the errorists\' movement from bad to worse: they advance, but in the direction of destruction. <em>Planōntes kai planōmenoi</em> (deceiving and being deceived) — the dual participle: the false teacher who deceives others is simultaneously self-deceived; deception is both inflicted and suffered.</p>',
    "14": '<p><em>Sy de mene en hois emathes kai epistōthēs</em> (but you, remain in what you have learned and have become convinced of): <em>mene</em> (remain, stay, abide) — the aorist imperative of steadfastness; Timothy is to remain fixed while the false teachers advance toward destruction. <em>Epistōthēs</em> (you have become firmly convinced) — the passive of <em>pistoō</em> (to make firm, make reliable); Timothy\'s conviction has been established by the process of learning from reliable sources. <em>Eidōs para tinōn emathes</em> (knowing from whom you learned) — the source matters; the reliability of the tradition depends on the reliability of the tradents.</p>',
    "15": '<p><em>Kai hoti apo brephous hiera grammata oidas</em> (and that from infancy you have known the holy scriptures): <em>brephos</em> (infant, very young child) — the earliest possible starting point; Timothy\'s formation in Scripture preceded his own ability to comprehend it (it was passed through his mother and grandmother, v. 5). <em>Hiera grammata</em> (sacred writings/scriptures) — the Jewish designation for the OT scriptures; this is the only NT use of <em>hiera grammata</em> in distinction from <em>graphē</em> (which appears in v. 16). The scriptures are described as <em>dynamena se sophisai eis sōtērian</em> (able to make you wise for salvation) — their functional purpose is wisdom-for-salvation rather than abstract knowledge.</p>',
    "16": '<p><em>Pasa graphē theopneustos</em> (all/every Scripture is God-breathed): <em>theopneustos</em> — a hapax legomenon in the NT, possibly coined by Paul or taken from Hellenistic Jewish usage. The compound <em>theos</em> + <em>pneō</em> (breathe): most naturally read as "breathed out by God" (God as the subject of the breathing, Scripture as the result) rather than "breathed into by God" (God breathing into an already-existing text). <em>Pasa graphē</em> — "all scripture" (every Scripture-text) or "the whole Scripture" (Scripture taken as a whole). Both readings affirm the universality of the claim. The four uses of Scripture — <em>didaskalia</em> (teaching), <em>elenchos</em> (reproof/refutation), <em>epanorthōsis</em> (correction/restoration), <em>paideia en dikaiosynē</em> (training in righteousness) — cover the full spectrum from instruction through discipline to formation.</p>',
    "17": '<p><em>Hina artios ē ho tou theou anthrōpos, pros pan ergon agathon exērtismenos</em> (so that the person of God may be complete/adequate, fully equipped for every good work): <em>artios</em> (complete, adequate, fitted) — the word for a thing that has all its parts in proper order; the perfect article, the complete vessel. <em>Exērtismenos</em> (fully equipped/furnished) — the perfect passive participle from <em>exartizō</em>, which shares the <em>artios</em> root; the doubling of the artios-root in this verse is deliberate: complete in being and fully equipped in capacity. The purpose of all Scripture\'s four functions (v. 16) is this single goal: the complete, equipped servant of God.</p>'
  },
  "4": {
    "1": '<p><em>Diamartyromai enōpion tou theou kai Christou Iēsou tou mellontos krinein zōntas kai nekrous</em> (I solemnly charge before God and Christ Jesus who is about to judge the living and the dead): <em>diamartyromai</em> (I solemnly testify, I charge solemnly) — the intensive compound; the charge is given before the highest possible witnesses: God and Christ Jesus as the eschatological Judge. <em>Zōntas kai nekrous</em> (the living and the dead) — the universal scope of the judgment; all humanity regardless of their status at the Parousia (cf. 1 Pet 4:5; Acts 10:42). <em>Kata tēn epiphaneian autou kai tēn basileian autou</em> (in view of / by his appearing and his kingdom) — the appearing and the kingdom are the twin eschatological realities that give the charge its urgency.</p>',
    "2": '<p><em>Kērykson ton logon</em> (herald the word): the bare imperative — no qualifications, no conditions; the herald proclaims regardless of circumstances. <em>Episthī eukairōs akairōs</em> (stand ready in season and out of season) — <em>eukairōs</em> (at the right time, in season) and <em>akairōs</em> (at the wrong time, out of season): the herald is ready when the audience is receptive and when they are not. <em>Elenxon, epitimēson, parakaleson</em> (reprove, rebuke, encourage) — three aorist imperatives covering the full ministerial range: reprove error (<em>elenchō</em>), rebuke personal sin (<em>epitimaō</em>), encourage the discouraged (<em>parakaleō</em>). <em>En pasē makrothymia kai didachē</em> (with all patience and teaching) — the manner that accompanies all three: patient and instructional rather than impulsive.</p>',
    "3": '<p><em>Estai gar kairos hote tēs hygiainousēs didaskalias ouk anexontai</em> (for there will be a time when they will not endure sound teaching): the prediction echoes the last-days framework of ch. 3; the inability to endure sound teaching is itself one of the signs of the difficult times. <em>Kata tas idias epithumias heautois episōreuousin didaskalous</em> (according to their own desires they heap up for themselves teachers) — <em>episōreuō</em> (to heap up, accumulate) — the appetite-driven accumulation of teachers who confirm what the audience already wants to hear. <em>Knēthomenoi tēn akoēn</em> (having their hearing scratched/tickled) — the image of the ear-itch that wants to be scratched; the audience selects teachers who provide the satisfaction of agreeable stimulation rather than the discomfort of truth.</p>',
    "4": '<p><em>Apo men tēs alētheias tēn akoēn apostrepsousin, epi de tous mythous ektraperontai</em> (they will turn their hearing from truth and will turn aside to myths): the double verb of turning — <em>apostrephō</em> (to turn away from) and <em>ektrepō</em> (to turn aside toward); the movement is away from truth and toward myths simultaneously. <em>Mythous</em> (myths) — the contrast between <em>alētheia</em> (truth) and <em>mythos</em> (myth/story) is a standard Platonic and Stoic distinction; the Pastoral Epistles use <em>mythos</em> for the false teachers\' genealogies and speculations (1 Tim 1:4; 4:7; Tit 1:14).</p>',
    "5": '<p><em>Sy de nēphe en pasin, kakopathēson, ergon poiēson euangelistou, tēn diakonian sou plērophorēson</em> (but you, be sober-minded in all things, endure hardship, do the work of an evangelist, fulfill your ministry): four aorist imperatives stacked against the drifting audience of vv. 3-4. <em>Nēphō</em> (to be sober, clear-headed) — the watchfulness that keeps Timothy alert when the surrounding culture is intoxicated with comfortable teaching. <em>Plērophorēson tēn diakonian sou</em> (fulfill/fully discharge your ministry) — <em>plērophoreō</em> (to fill completely, fully accomplish); the ministry is not partially discharged but brought to full completion.</p>',
    "6": '<p><em>Egō gar ēdē spendomai kai ho kairos tēs analyseōs mou ephestēken</em> (for I am already being poured out as a drink offering and the time of my departure has come): <em>spendomai</em> (I am being poured out as a libation) — the present passive of <em>spendō</em> (to pour a libation at sacrifice); Paul\'s death is the libation poured at the conclusion of his sacrificial ministry (cf. Phil 2:17: spendomai epi tē thysią, where it is an addition to others\' sacrifice; here Paul is the sacrifice itself). <em>Analysis</em> (departure) — <em>analuō</em> means to loosen, untie, dissolve; it is the loosing of a ship\'s moorings to depart, or the striking of a tent for departure; an image of release rather than annihilation.</p>',
    "7": '<p><em>Ton kalon agōna ēgōnismai, ton dromon tetelekas, tēn pistin tetērēka</em> (I have fought the good fight, I have finished the race, I have kept the faith): three perfect indicatives — <em>ēgōnismai, tetelekas, tetērēka</em> — describing completed action with present relevance. The triple perfect is the literary high point of the letter: a life summarized in three images. <em>Kalos agōn</em> (good fight/contest) — the same phrase as 1 Tim 6:12; now Paul uses it of his own completed career. <em>Dromos</em> (race/course) — the athletic course run to completion. <em>Pistin tetērēka</em> (I have kept the faith) — faith as a deposit kept, echoing <em>parathēkē</em> (deposit to guard) from 1:12-14.</p>',
    "8": '<p><em>Loipon apokeitai moi ho tēs dikaiosynēs stephanos</em> (henceforth there is stored/laid up for me the crown of righteousness): <em>apokeitai</em> (is laid away, stored) — the crown is in eschatological storage, reserved for its recipient. <em>Stephanos dikaiosynēs</em> (crown of righteousness) — the victor\'s wreath made of righteousness; either the crown that righteousness produces or the crown that the righteous Judge awards. <em>Ho dikaios kritēs</em> (the righteous Judge) — Christ as the impartial eschatological judge whose verdict corresponds to reality. <em>Pasin tois ēgapēkosi tēn epiphaneian autou</em> (to all who have loved his appearing) — the crown is not exclusive to Paul but awarded to all who love the Parousia.</p>',
    "9": '<p><em>Spoudason elthein pros me tacheos</em> (make every effort to come to me soon): <em>spoudazō</em> (to be diligent, make haste, earnestly endeavor) + <em>tacheos</em> (quickly, soon) — the urgency of the summons. The personal request for Timothy\'s presence after the solemn peroration of vv. 6-8 grounds the theology in the practical humanity of the imprisoned apostle who wants his beloved companion near. The letter oscillates between the universal (the eschatological judge, the crown for all believers) and the particular (come before winter, bring the cloak).</p>',
    "10": '<p><em>Dēmas gar me enkatelipe agapēsas ton nyn aiōna</em> (for Demas has deserted me, having loved the present age): <em>agapēsas ton nyn aiōna</em> (having loved the present age) — the aorist participle gives the theological reason for desertion. <em>Ton nyn aiōna</em> (the present age) — the current world order in its temporal, passing character; Demas chose love of the present age over solidarity with Paul who was suffering for the coming age. Demas appears in Philemon 24 and Col 4:14 as a fellow worker; his desertion is the more poignant for his prior close association with Paul.</p>',
    "11": '<p><em>Loukas estin monos met\' emou</em> (Luke alone is with me): the stark isolation — only Luke, the physician and author of Luke-Acts (cf. Col 4:14), remains. <em>Markon analabōn age meta seautou</em> (take Mark and bring him with you) — Mark (John Mark) had been a point of contention between Paul and Barnabas (Acts 15:37-39); his rehabilitation is marked here by Paul\'s warm commendation: <em>estin gar moi euchrēstos eis diakonian</em> (he is useful to me for ministry). The same adjective <em>euchrēstos</em> (useful) appears in 2:21 for the honored vessel; Mark has become the useful, honored vessel.</p>',
    "12": '<p><em>Tychikon de apesteila eis Epheson</em> (Tychicus I sent to Ephesus): Tychicus appears as Paul\'s messenger in Eph 6:21-22, Col 4:7-8, Tit 3:12, and Acts 20:4 — a trusted emissary dispatched for specific missions. The sending of Tychicus to Ephesus (Timothy\'s location) may explain Timothy\'s being freed to come to Rome: his replacement has been dispatched. The letter\'s practical network of colleagues and messengers reveals the organizational complexity of Paul\'s mission.</p>',
    "13": '<p><em>Ton phelonēn hon apelipon en Trōadi para Karpō</em> (the cloak I left at Troas with Carpus): <em>phelonēs</em> (cloak, travelling coat) — a heavy outer garment for warmth and weather protection; essential for a Roman winter. The request has pastoral import: Paul is cold in prison and winter is coming (v. 21). <em>Kai ta biblia, malista tas membranas</em> (and the books, especially the parchments) — <em>biblia</em> may be papyrus scrolls of Scripture or documents; <em>membranas</em> (parchments, membranae) is a Latin loanword, referring to the animal-skin writing surfaces; the parchments may be Paul\'s personal copies of Scripture or important documents. The apostle in prison wants his books.</p>',
    "14": '<p><em>Alexandros ho chalkeus polla moi kaka enedeixato</em> (Alexander the metalworker/coppersmith did me a great deal of harm): <em>chalkeus</em> = worker in copper/bronze; possibly the Alexander of 1 Tim 1:20 (though a common name). <em>Apodōsei autō ho Kyrios kata ta erga autou</em> (the Lord will repay him according to his works) — the passive future <em>apodōsei</em> (will repay) leaves vengeance to divine justice rather than claiming personal retribution; Paul cites the principle of Prov 24:12 / Ps 62:12 (God repays according to deeds). The tone is judicial rather than vindictive.</p>',
    "15": '<p><em>Hon kai sy phylassou</em> (whom you also guard against): the singular imperative of watchfulness. <em>Lian gar antestē tois hēmeterois logois</em> (for he strongly opposed our words/message) — <em>lian</em> (greatly, exceedingly) intensifies the opposition; <em>antestē</em> (he withstood, opposed) is the same verb used in v. 8 for Jannes and Jambres opposing Moses. The pattern of opposition to apostolic teaching has a type (the Egyptian magicians), a local instance (Alexander), and a universal principle (the last-days difficult times).</p>',
    "16": '<p><em>En tē prōtē mou apologia oudeis moi paregento</em> (at my first defense no one supported me): <em>apologia</em> (defense, formal legal defense) — the Roman judicial proceeding where the defendant makes their case; <em>prōtē</em> (first) implies there was a subsequent hearing. <em>Pantes me enkatelipon</em> (everyone deserted me) — the same verb as v. 10 (Demas deserted); Paul was abandoned at his most critical moment. <em>Mē autois logistheiē</em> (may it not be held against them) — the optative of forgiveness echoing Stephen\'s prayer (Acts 7:60) and Jesus\'s cross-word (Luke 23:34).</p>',
    "17": '<p><em>Ho de Kyrios moi parestē kai enedynamōsen me</em> (but the Lord stood alongside me and strengthened me): the contrast with v. 16 — humans deserted, but the Lord stood <em>beside</em> (<em>parestē</em>) Paul; the same word used for a legal advocate standing alongside the defendant. <em>Hina di\' emou to kērygma plērophorēthē</em> (so that through me the proclamation might be fully made) — even at his first defense, Paul\'s purpose is proclamation: the trial becomes a preaching opportunity before the Gentile powers (<em>panta ta ethnē akousē</em>). <em>Errysthēn ek stomatos leontos</em> (I was rescued from the lion\'s mouth) — Ps 22:21 language; the lion may be a metaphor for the Roman court, Nero, or the devil (cf. 1 Pet 5:8).</p>',
    "18": '<p><em>Ryssetai me ho Kyrios apo pantos ergou ponērou kai sōsei eis tēn basileian autou tēn epouranion</em> (the Lord will rescue me from every evil attack and will save me into his heavenly kingdom): the future tense: not rescue from physical death (Paul expects death, v. 6-7) but rescue through death into the kingdom. <em>Ergou ponērou</em> (evil work/attack) — the evil that would destroy Paul\'s ultimate standing, not merely his physical life. <em>Tēn basileian tēn epouranion</em> (the heavenly kingdom) — the kingdom Paul will enter through death; the kingdom is already present in Christ but its final form is the eschatological destination. <em>Hō hē doxa eis tous aiōnas tōn aiōnōn</em> — the doxological response triggered by confidence in divine rescue.</p>',
    "19": '<p><em>Aspasai Priskan kai Akylān</em> (greet Prisca and Aquila): the notable pair mentioned in Romans 16:3, 1 Corinthians 16:19, and Acts 18:2, 18, 26; Priscilla (here "Prisca") is named first, as often — an indication of her prominence in the ministry partnership. They are apparently back in Ephesus (they had been in Corinth and Rome at various points). <em>Kai ton Onēsiphorou oikon</em> (and the household of Onesiphorus) — the same person praised in 1:16-18; the greeting to his household (rather than to Onesiphorus himself) may imply his death.</p>',
    "20": '<p><em>Erastos emeinen en Korinthō, Trophimon de apelipon en Milētō asthenounta</em> (Erastus remained in Corinth, and Trophimus I left sick at Miletus): the practical logistics of Paul\'s last journey. Erastus appears in Acts 19:22 and Rom 16:23 (where he is the city treasurer of Corinth — a significant civic position). Trophimus appears in Acts 20:4 and 21:29 (an Ephesian, whose presence in the temple precincts triggered Paul\'s arrest). The detail that Paul left Trophimus sick (<em>asthenounta</em>) is significant: despite the Spirit\'s gifts of healing in the church, Paul did not simply heal his colleague — illness remains a reality within the community of faith.</p>',
    "21": '<p><em>Spoudason pro cheimōnos elthein</em> (make every effort to come before winter): the practical urgency — winter made Mediterranean sea travel impossible (roughly from October to March; Acts 27:9-12 illustrates the danger). If Timothy did not arrive before winter, he could not come until spring, by which time Paul\'s execution might have occurred. <em>Aspazontai se Eubulos kai Poudens kai Linos kai Klaudia kai hoi adelphoi pantes</em> — the named Roman Christians: Pudens and Claudia appear in later tradition as early British converts (Tertullian); Linus appears in Irenaeus\'s list as the first bishop of Rome after Peter and Paul. These details, if authentic, connect the letter directly to the Roman church around the time of Paul\'s martyrdom.</p>',
    "22": '<p><em>Ho Kyrios meta tou pneumatos sou</em> (the Lord be with your spirit): the singular <em>sou</em> (your, singular) addresses Timothy specifically — a personal benediction for the individual minister. <em>Hē charis meth\' hymōn</em> (grace be with you all) — the plural <em>hymōn</em> signals the public reading dimension: behind the individual addressee is the congregation. The double closing — one singular, one plural — captures the letter\'s dual address throughout: Timothy the individual leader and the Ephesian community he serves. The brevity of the closing (<em>hē charis</em> alone, without doxology) matches the letter\'s tone of urgent intimacy.</p>'
  }
}

def main():
    existing = load_comm('mkt-original', '2timothy')
    merge_comm(existing, ORIGINAL)
    save_comm('mkt-original', '2timothy', existing)

    il = json.loads((ROOT / 'data' / 'interlinear' / '2timothy.json').read_text())
    all_ok = True
    for ch in ['1', '2', '3', '4']:
        ck = str(ch)
        il_vv = set(il.get(ck, {}).keys())
        out_vv = set(existing.get(ck, {}).keys())
        missing = il_vv - out_vv
        if missing:
            print(f'  ch{ch} still missing: {sorted(missing, key=int)}')
            all_ok = False
        else:
            print(f'  ch{ch}: complete ({len(out_vv)} verses)')
    if all_ok:
        print('All 2 Timothy original entries present ✓')

if __name__ == '__main__':
    main()
